SELECT count(*) FROM movie_companies, company_name, title, company_type, movie_info, kind_type, movie_keyword, cast_info, keyword WHERE movie_companies.company_id = company_name.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_info.movie_id = title.id AND title.kind_id = kind_type.id AND movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id AND movie_keyword.keyword_id = keyword.id;